app = Flask(__name__)

# AWS Configuration
S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-service-bucket')
AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')

# Security Configuration
ALLOWED_SCHEMES = ['http', 'https']
BLOCKED_IP_RANGES = [
    ipaddress.ip_network('10.0.0.0/8'),
    ipaddress.ip_network('172.16.0.0/12'),
    ipaddress.ip_network('192.168.0.0/16'),
    ipaddress.ip_network('127.0.0.0/8'),
    ipaddress.ip_network('169.254.0.0/16'),
    ipaddress.ip_network('::1/128'),
    ipaddress.ip_network('fc00::/7'),
    ipaddress.ip_network('fe80::/10'),
]

TIMEOUT_SECONDS = 30
MAX_REDIRECTS = 3

s3_client = boto3.client('s3', region_name=AWS_REGION)


class SSRFProtectionError(Exception):
    pass


def validate_url_format(url: str) -> str:
    """Validate URL format and scheme"""
    if not url or not isinstance(url, str):
        raise ValueError("Invalid URL format")
    
    url = url.strip()
    
    # Check for basic URL structure
    if not re.match(r'^https?://', url, re.IGNORECASE):
        raise ValueError("URL must start with http:// or https://")
    
    # Parse URL
    try:
        parsed = urllib.parse.urlparse(url)
    except Exception:
        raise ValueError("Invalid URL format")
    
    # Validate scheme
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError(f"Scheme must be one of {ALLOWED_SCHEMES}")
    
    # Validate hostname exists
    if not parsed.netloc:
        raise ValueError("URL must contain a valid hostname")
    
    # Check for suspicious patterns
    if '@' in parsed.netloc:
        raise ValueError("URL contains suspicious characters")
    
    # Prevent localhost variations
    hostname = parsed.hostname
    if not hostname:
        raise ValueError("Invalid hostname")
    
    hostname_lower = hostname.lower()
    blocked_hostnames = [
        'localhost',
        'metadata.google.internal',
        '169.254.169.254',
    ]
    
    for blocked in blocked_hostnames:
        if blocked in hostname_lower:
            raise SSRFProtectionError(f"Access to {hostname} is not allowed")
    
    return url


def resolve_and_validate_ip(hostname: str) -> str:
    """Resolve hostname to IP and validate it's not internal"""
    try:
        # Get all IP addresses for the hostname
        addr_info = socket.getaddrinfo(hostname, None)
        
        for info in addr_info:
            ip_str = info[4][0]
            
            try:
                ip_obj = ipaddress.ip_address(ip_str)
                
                # Check if IP is in blocked ranges
                for blocked_range in BLOCKED_IP_RANGES:
                    if ip_obj in blocked_range:
                        raise SSRFProtectionError(
                            f"Access to internal IP address {ip_str} is not allowed"
                        )
                
                # Check for loopback
                if ip_obj.is_loopback:
                    raise SSRFProtectionError("Access to loopback addresses is not allowed")
                
                # Check for private addresses
                if ip_obj.is_private:
                    raise SSRFProtectionError("Access to private IP addresses is not allowed")
                
                # Check for link-local
                if ip_obj.is_link_local:
                    raise SSRFProtectionError("Access to link-local addresses is not allowed")
                
                # Check for multicast
                if ip_obj.is_multicast:
                    raise SSRFProtectionError("Access to multicast addresses is not allowed")
                
            except ValueError:
                continue
        
        return hostname
        
    except socket.gaierror:
        raise ValueError(f"Could not resolve hostname: {hostname}")
    except Exception as e:
        raise ValueError(f"Error validating hostname: {str(e)}")


def validate_url_ssrf(url: str) -> str:
    """Complete SSRF validation for URL"""
    # First validate format
    url = validate_url_format(url)
    
    # Parse and validate hostname
    parsed = urllib.parse.urlparse(url)
    hostname = parsed.hostname
    
    # Resolve and validate IP
    resolve_and_validate_ip(hostname)
    
    return url


def setup_chrome_driver() -> webdriver.Chrome:
    """Setup headless Chrome driver with security options"""
    chrome_options = Options()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--no-sandbox')
    chrome_options.add_argument('--disable-dev-shm-usage')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--window-size=1920,1080')
    chrome_options.add_argument('--disable-web-security')
    chrome_options.add_argument('--disable-features=VizDisplayCompositor')
    
    # Security options
    chrome_options.add_argument('--disable-extensions')
    chrome_options.add_argument('--disable-plugins')
    chrome_options.add_argument('--disable-java')
    
    # Prevent access to local files
    chrome_options.add_argument('--disable-file-system')
    
    prefs = {
        'profile.default_content_setting_values': {
            'notifications': 2,
            'geolocation': 2,
        }
    }
    chrome_options.add_experimental_option('prefs', prefs)
    
    driver = webdriver.Chrome(options=chrome_options)
    driver.set_page_load_timeout(TIMEOUT_SECONDS)
    
    return driver


def capture_screenshot(url: str) -> Tuple[bytes, str]:
    """Capture screenshot of URL and return image bytes and format"""
    driver = None
    
    try:
        # Validate URL for SSRF
        validated_url = validate_url_ssrf(url)
        
        # Setup driver
        driver = setup_chrome_driver()
        
        # Navigate to URL
        driver.get(validated_url)
        
        # Wait for page to load
        driver.implicitly_wait(5)
        
        # Take screenshot
        screenshot_bytes = driver.get_screenshot_as_png()
        
        # Create thumbnail
        image = Image.open(io.BytesIO(screenshot_bytes))
        
        # Resize to thumbnail (maintain aspect ratio)
        thumbnail_size = (400, 300)
        image.thumbnail(thumbnail_size, Image.Resampling.LANCZOS)
        
        # Convert to bytes
        output = io.BytesIO()
        image.save(output, format='PNG', optimize=True)
        thumbnail_bytes = output.getvalue()
        
        return thumbnail_bytes, 'png'
        
    except SSRFProtectionError as e:
        raise SSRFProtectionError(str(e))
    except TimeoutException:
        raise Exception("Page load timeout exceeded")
    except WebDriverException as e:
        raise Exception(f"Browser error: {str(e)}")
    except Exception as e:
        raise Exception(f"Screenshot capture failed: {str(e)}")
    finally:
        if driver:
            try:
                driver.quit()
            except:
                pass


def upload_to_s3(image_bytes: bytes, file_extension: str) -> str:
    """Upload screenshot to S3 and return URL"""
    try:
        # Generate unique filename
        filename = f"screenshots/{uuid.uuid4()}.{file_extension}"
        
        # Upload to S3
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=filename,
            Body=image_bytes,
            ContentType=f'image/{file_extension}',
            ACL='public-read'
        )
        
        # Generate URL
        s3_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{filename}"
        
        return s3_url
        
    except Exception as e:
        raise Exception(f"S3 upload failed: {str(e)}")


