@app.route('/screenshot', methods=['POST'])
def create_screenshot():
    """Create screenshot from URL"""
    try:
        # Get URL from request
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        
        # Capture screenshot with SSRF protection
        try:
            image_bytes, file_extension = capture_screenshot(url)
        except SSRFProtectionError as e:
            return jsonify({'error': f'Security violation: {str(e)}'}), 403
        except Exception as e:
            return jsonify({'error': str(e)}), 400
        
        # Upload to S3
        try:
            s3_url = upload_to_s3(image_bytes, file_extension)
        except Exception as e:
            return jsonify({'error': str(e)}), 500
        
        return jsonify({
            'success': True,
            'screenshot_url': s3_url,
            'original_url': url
        }), 200
        
    except BadRequest:
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500


@app.route('/screenshot/batch', methods=['POST'])
def create_screenshots_batch():
    """Create screenshots for multiple URLs"""
    try:
        data = request.get_json()
        
        if not data or 'urls' not in data:
            return jsonify({'error': 'URLs array is required'}), 400
        
        urls = data['urls']
        
        if not isinstance(urls, list):
            return jsonify({'error': 'URLs must be an array'}), 400
        
        if len(urls) > 10:
            return jsonify({'error': 'Maximum 10 URLs per batch'}), 400
        
        results = []
        
        for url in urls:
            try:
                image_bytes, file_extension = capture_screenshot(url)
                s3_url = upload_to_s3(image_bytes, file_extension)
                
                results.append({
                    'url': url,
                    'success': True,
                    'screenshot_url': s3_url
                })
            except SSRFProtectionError as e:
                results.append({
                    'url': url,
                    'success': False,
                    'error': f'Security violation: {str(e)}'
                })
            except Exception as e:
                results.append({
                    'url': url,
                    'success': False,
                    'error': str(e)
                })
        
        return jsonify({
            'results': results
        }), 200
        
    except BadRequest:
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500


